import React, { createContext, useContext, useMemo } from 'react';
import PropTypes from 'prop-types';

/**
 * @typedef {Object} ListProviderProps
 * @prop {React.ReactNode} children
 * @prop {'checkbox' | 'listbox' | 'radio' | 'standalone'} [listType]
 */

/**
 * @typedef {Object} ListContextType
 * @prop {'checkbox' | 'listbox' | 'radio' | 'standalone'} [listType]
 */

/** @type {React.Context<ListContextType>} */
export const ListContext = createContext(/** @type {ListContextType} */({}));

export function useListContext() {
  return useContext(ListContext);
}

/** @type {(props: ListProviderProps) => React.ReactNode} */
export function ListProvider({ children, listType }) {
  const value = useMemo(() => ({ listType }), [listType]);

  return (
    <ListContext.Provider value={value}>
      {children}
    </ListContext.Provider>
  );
}

ListProvider.propTypes = {
  children: PropTypes.node,
  listType: PropTypes.oneOf(['checkbox', 'listbox', 'radio', 'standalone']),
};
